func thumbActive(i int) string {
	if i == 0 {
		return "active"
	}
	return ""
}

func compareAtFor(vs []*models.Variant) float64 {
	for _, v := range vs {
		if v.IsDefault && v.CompareAtPrice != nil {
			return *v.CompareAtPrice
		}
	}
	for _, v := range vs {
		if v.CompareAtPrice != nil {
			return *v.CompareAtPrice
		}
	}
	return 0
}

func percentOff(was, now float64) string {
	if was <= 0 || now >= was {
		return "0"
	}
	pct := int(((was - now) / was) * 100)
	return intToString(pct)
}

func deref(s *string) string {
	if s == nil {
		return ""
	}
	return *s
}

func defaultSKU(vs []*models.Variant) string {
	for _, v := range vs {
		if v.IsDefault {
			return v.SKU
		}
	}
	if len(vs) > 0 {
		return vs[0].SKU
	}
	return "-"
}

func stockLabel(n int) string {
	if n <= 0 {
		return "Habis"
	}
	return intToString(n) + " tersedia"
}

func weightLabel(g int) string {
	if g >= 1000 {
		return floatStr(float64(g)/1000.0) + " kg"
	}
	return intToString(g) + " g"
}

func floatStr(v float64) string {
	intPart := int(v)
	frac := int((v - float64(intPart)) * 100)
	if frac == 0 {
		return intToString(intPart)
	}
	return intToString(intPart) + "." + intToString(frac)
}

func variantLabel(v *models.Variant) string {
	if v.Name != nil && *v.Name != "" {
		return *v.Name
	}
	return v.SKU
}

func waLink(num, name, url string) templ.SafeURL {
	digits := ""
	for i := 0; i < len(num); i++ {
		c := num[i]
		if c >= '0' && c <= '9' {
			digits += string(c)
		}
	}
	msg := "Halo, saya tertarik dengan produk: " + name + "\n" + url
	encoded := ""
	for i := 0; i < len(msg); i++ {
		c := msg[i]
		switch {
		case c == ' ':
			encoded += "%20"
		case c == '\n':
			encoded += "%0A"
		case c == ':':
			encoded += "%3A"
		case c == '/':
			encoded += "%2F"
		default:
			encoded += string(c)
		}
	}
	return templ.SafeURL("https://wa.me/" + digits + "?text=" + encoded)
}

